package evaluation

import (
	"fmt"
)

// EvaluationError wraps storage and evaluation errors with context about which
// flag and namespace was being evaluated, and at which phase the error occurred.
type EvaluationError struct {
	// Namespace is the namespace key being evaluated
	Namespace string
	// Flag is the flag key being evaluated
	Flag string
	// Phase describes which phase of evaluation failed (e.g., "rules", "distributions", "rollouts")
	Phase string
	// Err is the underlying error that occurred
	Err error
}

// Error implements the error interface.
func (e *EvaluationError) Error() string {
	return fmt.Sprintf("evaluation error [namespace=%s flag=%s phase=%s]: %v",
		e.Namespace, e.Flag, e.Phase, e.Err)
}

// Unwrap returns the underlying error, enabling error chain inspection with errors.Unwrap().
func (e *EvaluationError) Unwrap() error {
	return e.Err
}

// NewEvaluationError creates a new evaluation error wrapping the given error with context.
func NewEvaluationError(namespace, flag, phase string, err error) *EvaluationError {
	return &EvaluationError{
		Namespace: namespace,
		Flag:      flag,
		Phase:     phase,
		Err:       err,
	}
}

